        "job_title": "Assistant Cook – Butcher",
        "slug": "ligabue-assistant-cook-butcher",
        "priority": 3,
        "address": null,
        "company_name": "Ligabue",
        "industry_name": "Catering",
        "is_active": 1,
        "salary_type": "monthly",
        "currency": "SAR",
        "min_salary": 1800,
